sourcesContent:
import React from 'react';
import classNames from 'classnames';

var AppMain = React.createClass({
  getInitialState() {
    return {
      sports: [
        {
          title: 'nfl',
          games: [
            {
              state: 'final',
              homeTeam: { abbrev: 'car', score: '21', logo: '' },
              awayTeam: { abbrev: 'phi', score: '6', logo: '' }
            },
            {
              state: 'final',
              homeTeam: { abbrev: 'pit', score: '14', logo: ''},
              awayTeam: { abbrev: 'ne', score: '31', logo: ''}
            }
          ]
        }
      ]
    };
  },
  render() {
    let { sports } = this.state;

    let data = [];
    for (let i = 0; i < sports.length; i++) {
      let sport = sports[i];
      data.push(
        <li className={classNames('sport-title-wrap', 'scores-slide')} data-sport={sport.title.toLowerCase()}>
          <div className={classNames('sport-title', sport.title.toLowerCase()+'-text')} >{sport.title}</div>
        </li>
      );

      for (let j = 0; j < sport.games.length; j++) {
        let game = sport.games[j];
        data.push(
          <li className={classNames('score-wrap', 'scores-slide')} data-sport={sport.title.toLowerCase()}>
            <div className='score'>
              <div className='game-state'>
                {game.state}
              </div>
              <div className='home-team'>
                <span className='abbrev'>{game.homeTeam.abbrev}</span>
                <span className='score-val'>{game.homeTeam.score}</span>
              </div>
              <div className='away-team'>
                <span className='abbrev'>{game.awayTeam.abbrev}</span>
                <span className='score-val'>{game.homeTeam.score}</span>
              </div>
            </div>
          </li>
        );
      }
    }

    return (
          <ul className='scores-wrap'>
            {data}
          </ul>
    );
  },
  _setSport(sport, component) {
    if (!component) {
      return;
    } else {
      const element = component.getDOMNode();
      element.setAttribute('data-'+(sport.toLowerCase()), sport);
    }
  }
});

export default AppMain;

