import React from 'react';
import classNames from 'classnames';

let Chunk = React.createClass({
  getInitialState() {
    return {
      sports: [
        {
          title: 'NFL',
          games: [
            {
              state: 'FINAL',
              homeTeam: { abbrev: 'CAR', score: '21', logo: '' },
              awayTeam: { abbrev: 'PHI', score: '6', logo: '' }
            },
            {
              state: 'FINAL',
              homeTeam: { abbrev: 'PIT', score: '14', logo: ''},
              awayTeam: { abbrev: 'NE', score: '31', logo: ''}
            }
          ]
        }
      ]
    };
  },
  render() {
    let { sports } = this.state;

    let data = [];
    for (let i = 0; i < sports.length; i++) {
      let sport = sports[i];
      data.push(
        <li className={classNames('sport-title-wrap', 'scores-slide')}>
          <div className={classNames('sport-title', sport.className)}>{sport.title}</div>
        </li>
      );
      for (let j = 0; j < sport.games.length; j++) {
        let game = sport.games[j];
        data.push(
          <li className={classNames('score-wrap', 'scores-slide')}>
            <div className='score'>
              <div className='game-state'>
                {game.state}
              </div>
              <div className='home-team'>
                <span className='abbrev'>{game.homeTeam.abbrev}</span>
                <span className='score-val'>{game.homeTeam.score}</span>
              </div>
              <div className='away-team'>
                <span className='abbrev'>{game.awayTeam.abbrev}</span>
                <span className='score-val'>{game.homeTeam.score}</span>
              </div>
            </div>
          </li>
        );
      }
    }

    return (
      <div className='scores-outer'>
        <div classNames='scores-container'>
          <ul className='scores-wrap'>
            {data}
          </ul>
        </div>
      </div>
    );
  }
});

export default Chunk;

