import React from 'react';
import classNames from 'classnames';
import util from 'app/data-providers/util.js';

var appPaths = require("../root.js").paths;

let provider = util.getSampleProvider();

var AppMain = React.createClass({
  propTypes: {
    sportProp: React.PropTypes.string
  },
  statics: {
    requestData: function(props) {
      this.setState({
        scores: provider.getScores(props.sportProp)
      });
    }
  },
  getDefaultProps() {
    return {
      sportProp: 'all'
    };
  },
  getInitialState() {
    return {
      scores: [
        {
          title: 'nfl',
          games: [
            {
              state: 'final',
              homeTeam: { abbrev: 'car', score: '21', logo: '' },
              awayTeam: { abbrev: 'phi', score: '6', logo: '' }
