import Dependencies from './Dependencies';

/*
  Similar to the data center concept in our backbone apps,
  this is where you retrieve data that get fed into react
  components.
*/

export default class DataProvider {

  constructor(deps) {
    this._deps = deps || (new Dependencies());
  }

  /* Define methods that derive data points below */

  getScores() {
    return this._deps.depends(
      ['scores', {}]
    ).then(
      ([scores]) => {
        return scores;
      }
    );
  }
}

