/*
  Responsible for resolving dependencies.
  Uses cache when possible, calls API when needed
*/
export default class Dependencies {

  constructor(api) {
    this._api = api || (new Api());
  }

  _loadScores(params) {
    return this.pending([
      ['scores']
    ], () => {
      return this._api.fetchScores()
        .then((scores) => {
          this._cache.set('scores', scores);
          return scores;
        });
      }
    );
  }

  loadDependency(name, params) {
    switch (name) {
      case 'scores':
        return this._loadScores(params);
    }
    return false;
  }
}

