import React from 'react';
import classNames from 'classnames';
import moment from 'moment';
import globalUtils from '../../utils/globalUtils.js';

var ScoreStrip = React.createClass({
  propTypes: {
    scores: React.PropTypes.array
  },
  render() {
    const { scores } = this.props;

    let stripElements = [];

    for (let i = 0; i < scores.length; i++) {
      let sport = Object.keys(scores[i])[0];
      stripElements.push(
        <li className={classNames('sport-title-wrap', 'scores-slide')} data-sport={sport.toLowerCase()}>
          <div className={classNames('sport-title', sport.toLowerCase()+'-text')} >{sport}</div>
        </li>
      );
      if (scores[i][sport] !== 'error') {
        for (let j = 0; j < scores[i][sport].length; j++) {
          let game = scores[i][sport][j];
          let homeWin = false;
          let awayWin = false;
          if (game.homeScore > game.awayScore) { homeWin = true; }
          if (game.awayScore > game.homeScore) { awayWin = true; }
          stripElements.push(
            <li className={classNames('score-wrap', 'scores-slide')} data-sport={sport.toLowerCase()}>
              <div className='score'>
                <div className='game-state'>
                  {globalUtils.ife(game.gameState === 'pre-event', () => {
                    return <span>{moment(game.gameStartDateTime).format("M/DD h:mm A")}</span>;
                  }, () => {
                    let state = game.gameState === 'post-event' ? 'final' : game.gameState;
                    return <span>{state}</span>;
                  })}
                </div>
                <div className={classNames('home-team', { 'winner': homeWin })}>
                  <span className={classNames('abbrev', sport.toLowerCase() + '-team-' + game.homeTeam.abbr.toLowerCase())}>{game.homeTeam.abbr}</span>
                  <span className='score-val'>{game.homeScore}</span>
                </div>
                <div className={classNames('away-team', { 'winner': awayWin })}>
                  <span className={classNames('abbrev', sport.toLowerCase() + '-team-' + game.awayTeam.abbr.toLowerCase())}>{game.awayTeam.abbr}</span>
                  <span className='score-val'>{game.awayScore}</span>
                </div>
              </div>
            </li>
          );
        }
      } else {
        stripElements.push(
          <li className={classNames('sport-title-wrap', 'scores-slide')} data-sport={sport.toLowerCase()}>
            <div className={classNames('sport-title', sport.toLowerCase()+'-text')} >{sport.toUpperCase() + ' Error'}</div>
          </li>
        );
      }
    }

    return (
      <div className='scores-container'>
        <ul className='scores-wrap'>
          {stripElements}
        </ul>
      </div>
    );
  }
});

export default ScoreStrip;

