var request = require('request');
var CommonTypes = require('../../app/data-providers/CommonTypes.js');

module.exports = function(req, res, next) {

  res.locals.scores = res.locals.scores || {};

  var apiUrl = 'http://api.nfl.onetwosee.xyz/schedule/live';

  request(apiUrl, function(err, response, body) {
    if (!err && response.statusCode === 200) {
       var scores = JSON.parse(body);

       res.locals.scores.nfl = scores.map((game) => {
        let homeTeam = new CommonTypes.Team({
          id: game.team[1].id,
          first: game.team[1].city,
          last: game.team[1].name,
          alignment: game.team[1].alignment,
          abbr: game.team[1].abbreviation
        });

        let awayTeam = new CommonTypes.Team({
          id: game.team[0].id,
          first: game.team[0].city,
          last: game.team[0].name,
          alignment: game.team[0].alignment,
          abbr: game.team[0].abbreviation
        });

        return new CommonTypes.Game({
          gameId: game.gameId,
          gameState: game.gameState,
          gameStartDateTime: game.gameStartDateTime,
          homeScore: game.homeScore,
          awayScore: game.awayScore,
          homeTeam: homeTeam,
          awayTeam: awayTeam
        });
      });

    } else {
      res.status(404).send('Page not found');
      return;
    }

    next();
  });
};

