import _ from 'underscore';

export class Entity {
  constructor(obj) {

  }
}

export class Team extends Entity {
  constructor(object) {
    super(object);
    _.extend(this, {
      id: 0,
      first: 'Team First',
      last: 'Team Last',
      alignment: 'UNK',
      color: '#777777',
      abbr: 'ZZZ',
      imageUrl: null
    }, object);
  }
}

export class Game extends Entity {
  constructor(object) {
    super(object);
    _.extend(this, {
      id: 0,
      gameState: 'pre-event',
      gameStartDateTime: '',
      homeScore: 0,
      awayScore: 0,
      homeTeam: new Team(),
      awayTeam: new Team()
    }, object);
  }
}

export default { Entity, Team, Game };

