var util = require('util');
var async = require('async');
var path = require('path');

// Use the sports array picked from the query string to build the array of fetch functions
module.exports = function(req, res, next) {
  if (req.renderTemplate !== 'application') {
    console.log(process.env.appDir);
    var fetchFunctions = {
      'nfl': require(path.join(process.env.appDir, '/fetchers/NflFetcher.js')).bind(this, req.nfl.provider, req.nfl.apiUrl),
      'mlb': require(path.join(process.env.appDir, '/fetchers/MlbFetcher.js')).bind(this, req.mlb.provider, req.mlb.apiUrl)
    };

    // req.sports is an array with the sports names, populate an array of fetch functions
    // that are bound to the data provider and apiUrl from the data-provider-config file,
    // skip any sports that don't exist
    var funcArray = [];
    console.log(req.sports);
    for (var i = 0; i < req.sports.length; i++) {
      if (fetchFunctions[req.sports[i]]) {
        funcArray.push(fetchFunctions[req.sports[i]]);
      }
    }
    // make sure we can create the scores array on the response
    res.locals.scores = [];
    // Async.paraallel kicks off all of the fetch functions at the same time
    // executes the results callback if they are successful
    async.parallel(
      funcArray, function(err, results) {
        if (!err) {

          // Set the scores array onto the response
          res.locals.scores = results;

          next();
        } else {
          util.log('You should never see this message.  Fetching errors are gracefully trapped before this point.');
        }
      }
    );
  } else {
    next();
  }
};

