import React from 'react';
import classNames from 'classnames';
import moment from 'moment';
import globalUtils from '../../utils/globalUtils.js';

var ScoreStrip = React.createClass({
  propTypes: {
    scores: React.PropTypes.array.isRequired,
    clickable: React.PropTypes.bool,
    targetOrigin: React.PropTypes.string,
    showLeagueBlock: React.PropTypes.bool,
    selectedIndex: React.PropTypes.number,
    onClick: React.PropTypes.func
  },
  getDefaultProps() {
    return {
      clickable: false,
      targetOrigin: '',
      selectedIndex: 0
    };
  },
  _handleGameClick(sport, _gameId, index) {
    return () => {
      this.props.onClick(sport, _gameId, index);
    };
  },
  componentDidMount() {
    const { selectedIndex } = this.props;
    if (!selectedIndex && selectedIndex !== 0) {
      let sport = this.props.scores[0].sport;
      let gameId = this.props.scores[0].games[0].gameId;
      this._handleGameClick(sport, gameId, 0)();
    }
  },
  render() {
    const { scores, clickable, showLeagueBlock, selectedIndex } = this.props;
    let stripElements = [];

    for (let i = 0; i < scores.length; i++) {
      let sport = scores[i].sport;
      if (showLeagueBlock) {
        stripElements.push(
          <li className={classNames('sport-title-wrap', 'scores-slide')} data-sport={sport.toLowerCase()}>
