var util = require('util');
var path = require('path');
var moment = require('moment');
var CommonTypes = require(path.resolve(process.env.appDir, 'data-providers', 'CommonTypes.js'));
var request = require('request');
var gameState = require(path.resolve(process.env.appDir, 'normalizers', 'gameState.js'));

module.exports = function(provider, apiUrl, now, cb) {
  var scoresObject = {};
  scoresObject.sport = 'nhl';

  var date = now;

  var options = {
    url: apiUrl + date.format('YYYY-MM-DD'),
    qs: {
      consumer: 'aol'
    }
  };

  if (provider === 'sportRadar') {
    request(options, function(err, response, body) {
      if (!err && response.statusCode === 200) {
          var data = JSON.parse(body);
          scoresObject.games = data.map((game) => {
            var homeTeam = new CommonTypes.Team({
              id: game.home.id,
              first: game.home.name,
              last: '',
              alignment: 'home',
              abbr: game.home.alias
            });

            var awayTeam = new CommonTypes.Team({
              id: game.away.id,
              first: game.away.name,
              last: '',
              alignment: 'away',
              abbr: game.away.alias
            });

            return new CommonTypes.Game({
              gameId: game.gameId,
              gameState: gameState(game.status),
              gameStartDateTime: game.gameStartDateTime,
              homeScore: game.home.points,
              awayScore: game.away.points,
              homeTeam: homeTeam,
              awayTeam: awayTeam
            });
          }
        );
        cb(null, scoresObject);
      } else {
        scoresObject.games = 'error';
        var error = JSON.parse(response.body);
        util.log(response.statusCode, error.code, error.message);
        cb(null, scoresObject);
      }
    });
  }
};

