    Returning 'pre' allows the component to return the scheduled time of the event instead
    of status
   */
  switch (status) {
    case 'pre-event':
      return 'pre';
    case 'mid-event':
      return 'live';
    case 'scheduled':
      return 'pre';
    case 'halftime':
      return 'half';
    case 'inprogress':
      return 'live';
    case 'created':
      return 'pre';
    case 'post-event':
      return 'final';
    case 'closed':
      return 'final';
    case 'complete':
      return 'final';
    case 'delayed':
     return 'delayed';
    case 'postponed':
      return 'postponed';
    case 'time-tbd':
      return 'time-tbd';
    case 'unnecessary':
      return 'canceled';
    case 'canceled':
      return 'canceled';
    default:
      return status;
  }
};
